/*\n  # Optimize Remaining RLS Policies - Part 3\n  \n  ## Tables Optimized (Part 3 of 4)\n  - optimized_resumes (3 policies)\n  - auto_apply_applications (4 policies)\n  - user_credentials_vault (4 policies)\n  - auto_apply_sessions (4 policies)\n  - auto_apply_analytics (3 policies)\n  - platform_sessions (4 policies)\n  - authentication_events (2 policies)\n  - automation_state (4 policies)\n  - blog_posts (4 policies)\n  - blog_categories (3 policies)\n  - blog_tags (3 policies)\n  - blog_post_categories (1 policy)\n  - blog_post_tags (1 policy)\n  - webinars (3 policies)\n  - webinar_speakers (3 policies)\n  - webinar_testimonials (3 policies)\n  - webinar_registrations (2 policies)\n  - webinar_updates (3 policies)\n  - webinar_update_views (2 policies)\n  - webinar_email_logs (1 policy)\n*/\n\n-- ============================================================================\n-- OPTIMIZED_RESUMES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own optimized resumes" ON public.optimized_resumes;
\nDROP POLICY IF EXISTS "Users can create own optimized resumes" ON public.optimized_resumes;
\nDROP POLICY IF EXISTS "Users can update own optimized resumes" ON public.optimized_resumes;
\nDROP POLICY IF EXISTS "Users can delete own optimized resumes" ON public.optimized_resumes;
\n\nCREATE POLICY "Users can view own optimized resumes" ON public.optimized_resumes\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own optimized resumes" ON public.optimized_resumes\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own optimized resumes" ON public.optimized_resumes\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own optimized resumes" ON public.optimized_resumes\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- AUTO_APPLY_APPLICATIONS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can view own applications" ON public.auto_apply_applications;
