\n\nCREATE POLICY "Users can view own applications" ON public.auto_apply_applications\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can create own applications" ON public.auto_apply_applications\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can update own applications" ON public.auto_apply_applications\n  FOR UPDATE TO authenticated\n  USING ((SELECT auth.uid()) = user_id)\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can delete own applications" ON public.auto_apply_applications\n  FOR DELETE TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
