\n\n-- ============================================================================\n-- BLOG_POSTS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Authenticated admins can view all blog posts" ON public.blog_posts;
\nDROP POLICY IF EXISTS "Only admins can insert blog posts" ON public.blog_posts;
\nDROP POLICY IF EXISTS "Only admins can update blog posts" ON public.blog_posts;
\nDROP POLICY IF EXISTS "Only admins can delete blog posts" ON public.blog_posts;
\n\nCREATE POLICY "Authenticated admins can view all blog posts" ON public.blog_posts\n  FOR SELECT TO authenticated\n  USING (is_admin((SELECT auth.uid())));
\n\nCREATE POLICY "Only admins can insert blog posts" ON public.blog_posts\n  FOR INSERT TO authenticated\n  WITH CHECK (is_admin((SELECT auth.uid())));
\n\nCREATE POLICY "Only admins can update blog posts" ON public.blog_posts\n  FOR UPDATE TO authenticated\n  USING (is_admin((SELECT auth.uid())))\n  WITH CHECK (is_admin((SELECT auth.uid())));
