\n\nCREATE POLICY "Users can read own registrations" ON public.webinar_registrations\n  FOR SELECT TO authenticated\n  USING ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Users can insert own registrations" ON public.webinar_registrations\n  FOR INSERT TO authenticated\n  WITH CHECK ((SELECT auth.uid()) = user_id);
\n\nCREATE POLICY "Admins and service role can update registrations" ON public.webinar_registrations\n  FOR UPDATE TO authenticated\n  USING (is_admin((SELECT auth.uid())) OR (SELECT auth.uid()) = user_id)\n  WITH CHECK (is_admin((SELECT auth.uid())) OR (SELECT auth.uid()) = user_id);
\n\n-- ============================================================================\n-- WEBINAR_UPDATES TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Admins can insert webinar updates" ON public.webinar_updates;
\nDROP POLICY IF EXISTS "Admins can update webinar updates" ON public.webinar_updates;
