\n\n-- ============================================================================\n-- WEBINAR_EMAIL_LOGS TABLE\n-- ============================================================================\n\nDROP POLICY IF EXISTS "Users can read own email logs" ON public.webinar_email_logs;
\n\nCREATE POLICY "Users can read own email logs" ON public.webinar_email_logs\n  FOR SELECT TO authenticated\n  USING (EXISTS (\n    SELECT 1 FROM public.webinar_registrations\n    WHERE webinar_registrations.id = webinar_email_logs.registration_id\n    AND webinar_registrations.user_id = (SELECT auth.uid())\n  ));
\n;
